import{_ as h,o as t,c as a,a0 as i}from"./chunks/framework.jwovEGr5.js";const s=JSON.parse('{"title":"Nhà hàng","description":"","frontmatter":{"title":"Nhà hàng"},"headers":[],"relativePath":"restaurant.md","filePath":"restaurant.md"}'),c={name:"restaurant.md"};function o(g,n,r,e,u,l){return t(),a("div",null,[...n[0]||(n[0]=[i('<h1 id="nha-hang" tabindex="-1">Nhà hàng <a class="header-anchor" href="#nha-hang" aria-label="Permalink to &quot;Nhà hàng&quot;">​</a></h1><p>Mô-đun <strong>Nhà hàng (Restaurant)</strong> trong ABNERP cung cấp giải pháp quản lý toàn diện dành riêng cho ngành nhà hàng và dịch vụ ăn uống. Từ quản lý bàn, thực đơn, gọi món đến thanh toán — tất cả được tích hợp trong một hệ thống duy nhất.</p><h2 id="quan-ly-nha-hang" tabindex="-1">Quản lý nhà hàng <a class="header-anchor" href="#quan-ly-nha-hang" aria-label="Permalink to &quot;Quản lý nhà hàng&quot;">​</a></h2><p><strong>Nhà hàng (Restaurant)</strong> là đối tượng trung tâm của mô-đun. Bạn có thể thiết lập thông tin chi tiết cho từng nhà hàng bao gồm tên, địa chỉ, giờ hoạt động, bàn và khu vực phục vụ. Hệ thống hỗ trợ quản lý nhiều nhà hàng hoặc chi nhánh trên cùng một giao diện, phù hợp với chuỗi nhà hàng.</p><p>Thực đơn (Menu) được cấu hình linh hoạt: mỗi món ăn là một mặt hàng (Item) trong hệ thống với giá bán, tồn kho nguyên liệu và công thức chế biến. Các món có thể được nhóm theo danh mục (khai vị, món chính, tráng miệng, đồ uống) để dễ dàng quản lý và phục vụ.</p><h2 id="đat-ban" tabindex="-1">Đặt bàn <a class="header-anchor" href="#đat-ban" aria-label="Permalink to &quot;Đặt bàn&quot;">​</a></h2><p><strong>Đặt bàn (Reservation)</strong> cho phép khách hàng đặt trước bàn trong nhà hàng. Nhân viên có thể tạo đặt bàn trực tiếp trên hệ thống hoặc khách hàng có thể đặt qua trang web tích hợp. Mỗi đặt bàn bao gồm: thời gian, số lượng khách, bàn được chỉ định và các yêu cầu đặc biệt. Hệ thống tự động kiểm tra tình trạng bàn trống và đề xuất bàn phù hợp, tránh tình trạng đặt chồng lịch.</p><h2 id="goi-mon" tabindex="-1">Gọi món <a class="header-anchor" href="#goi-mon" aria-label="Permalink to &quot;Gọi món&quot;">​</a></h2><p><strong>Gọi món (Order Entry)</strong> được thực hiện trực tiếp qua giao diện POS (Point of Sale) trực quan. Nhân viên phục vụ có thể:</p><ul><li>Chọn bàn và bắt đầu gọi món</li><li>Thêm/xóa/sửa món trong hóa đơn</li><li>Ghi chú yêu cầu đặc biệt (ăn chay, không bột ngọt, v.v.)</li><li>Gửi món đến bếp in (kitchen printer)</li><li>Chia hóa đơn theo khách hoặc bàn</li></ul><p>Mỗi thao tác gọi món đều được ghi nhận thời gian thực, cho phép quản lý theo dõi tiến độ phục vụ và thời gian chờ của khách.</p><h2 id="thanh-toan" tabindex="-1">Thanh toán <a class="header-anchor" href="#thanh-toan" aria-label="Permalink to &quot;Thanh toán&quot;">​</a></h2><p><strong>Thanh toán (Payment)</strong> hỗ trợ nhiều hình thức thanh toán: tiền mặt, thẻ tín dụng, thẻ ghi nợ, ví điện tử và chuyển khoản. Hệ thống tự động tính thuế, phí dịch vụ và giảm giá (theo % hoặc số tiền) cho từng hóa đơn. Sau khi thanh toán, hóa đơn được ghi nhận đầy đủ vào sổ kế toán và cập nhật tồn kho nguyên liệu tương ứng.</p><p>Báo cáo nhà hàng bao gồm: doanh thu theo ngày, doanh thu theo bàn, món bán chạy, thời gian phục vụ trung bình và hiệu quả nhân viên — giúp chủ nhà hàng đưa ra quyết định kinh doanh dựa trên dữ liệu thực tế.</p>',14)])])}const m=h(c,[["render",o]]);export{s as __pageData,m as default};
